import { PriorityQueue } from 'typescript-collections';

function solve(n, edges) {
    const graph = new Map();
    for (const [u, v, w] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ to: v, weight: w });
    }

    const dist = new Array(n).fill(-1);
    dist[0] = 0;

    const pq = new PriorityQueue((a, b) => a.cost - b.cost);
    pq.enqueue({ node: 0, cost: 0, flipped: false });

    while (!pq.isEmpty()) {
        const { node, cost, flipped } = pq.dequeue();
        if (node === n - 1) return cost;
        if (dist[node] < cost) continue;

        const edgesFromNode = graph.get(node) || [];
        for (const { to, weight } of edgesFromNode) {
            const newCost = cost + weight;
            if (dist[to] > newCost) {
                dist[to] = newCost;
                pq.enqueue({ node: to, cost: newCost, flipped: false });
            }
        }

        // Check if we can flip the edge that led us to this node
        if (!flipped) {
            // We need to find the edge that led us to this node
            // Since we don't track the previous edge, we need to simulate it
            // This is a limitation of the approach, but we can try to find the edge
            // that could have been flipped
            for (const [u, v, w] of edges) {
                if (v === node) {
                    const newCost = cost + 2 * w;
                    if (dist[node] > newCost) {
                        dist[node] = newCost;
                        pq.enqueue({ node: node, cost: newCost, flipped: true });
                    }
                }
            }
        }
    }

    return -1;
}

