import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int size = (int) n;
        List<List<Neighbor>> graph = new ArrayList<>();
        for (int i = 0; i < size; i++) {
            graph.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            long u = (long) edge[0];
            long v = (long) edge[1];
            long w = (long) edge[2];
            graph.get((int) u).add(new Neighbor((int) v, w));
        }

        long[] dist = new long[size];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;

        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingLong(state -> state.cost));
        pq.offer(new State(0, 0, false));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int node = current.node;
            long cost = current.cost;
            boolean flipped = current.flipped;

            if (node == size - 1) {
                return cost;
            }

            if (dist[node] < cost) {
                continue;
            }

            for (Neighbor neighbor : graph.get(node)) {
                long newCost = cost + neighbor.weight;
                if (dist[neighbor.to] > newCost) {
                    dist[neighbor.to] = newCost;
                    pq.offer(new State(neighbor.to, newCost, false));
                }
            }

            if (!flipped) {
                for (long[] edge : edges) {
                    long u = edge[0];
                    long v = edge[1];
                    long w = edge[2];
                    if (v == node) {
                        long newCost = cost + 2 * w;
                        if (dist[node] > newCost) {
                            dist[node] = newCost;
                            pq.offer(new State(node, newCost, true));
                        }
                    }
                }
            }
        }

        return -1;
    }

    static class Neighbor {
        int to;
        long weight;

        Neighbor(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    static class State {
        int node;
        long cost;
        boolean flipped;

        State(int node, long cost, boolean flipped) {
            this.node = node;
            this.cost = cost;
            this.flipped = flipped;
        }
    }
}
